module top_module(
  input [2:0] in,
  output [7:0] out
);reg [7:0] inverted_out;

  always @(*) begin
    case(in)
      3'b000: inverted_out = 8'b00000001;
      3'b001: inverted_out = 8'b00000010;
      3'b010: inverted_out = 8'b00000100;
      3'b011: inverted_out = 8'b00001000;
      3'b100: inverted_out = 8'b00010000;
      3'b101: inverted_out = 8'b00100000;
      3'b110: inverted_out = 8'b01000000;
      3'b111: inverted_out = 8'b10000000;
      default: inverted_out = 8'b00000000;
    endcase
  end

  assign out = inverted_out;

endmodule
